query:
-- Count total vehicles
SELECT COUNT(*) as total_vehicles FROM vehicles;

-- Count vehicles with NULL userId
SELECT COUNT(*) as vehicles_with_null_userid FROM vehicles WHERE userId IS NULL;

-- Count vehicles grouped by userId
SELECT userId, COUNT(*) as vehicle_count FROM vehicles GROUP BY userId ORDER BY vehicle_count DESC;

-- Find vehicles whose userId doesn't exist in users table (orphaned)
SELECT COUNT(*) as orphaned_vehicles FROM vehicles v WHERE v.userId NOT IN (SELECT id FROM users);

-- Show details of orphaned vehicles
SELECT v.id, v.userId, v.plateNumber, v.brand, v.model FROM vehicles v WHERE v.userId NOT IN (SELECT id FROM users) LIMIT 10;

